docs_path = var_call_MMyKqAbaWyK4YDL1TloCDU5l
with open(docs_path, 'r', encoding='utf-8') as f:
    docs = json.load(f)

citations = var_call_40BzmFCtkmqBlfex3QhJccEU

def extract_title(filename):
    return filename[:-4] if filename.endswith('.txt') else filename

results = []
for d in docs:
    text = d.get('text','')
    if not text:
        continue
    if re.search(r'physical activity', text, re.IGNORECASE) is None:
        continue
    header = text[:1200]
    if re.search(r'\b2016\b', header) is None:
        continue
    title = extract_title(d.get('filename',''))
    total = 0
    for rec in citations:
        if rec.get('title') == title:
            try:
                total = int(rec.get('total_citations',0))
            except:
                total = 0
            break
    results.append({'title': title, 'total_citations': total})

# dedupe
